mapper.select:
SELECT c.cctv_count, s.ttm_count, s.ttw_count, s.gnss_count, s.tm_count, s.rain_count FROM ( SELECT COUNT(*) AS cctv_count FROM tb_cctv_info WHERE del_yn IS DISTINCT FROM 'Y'
and district_no = #{district_no}
) c CROSS JOIN ( SELECT COUNT(*) FILTER (WHERE tsi.sens_nm LIKE 'TTM%') AS ttm_count, COUNT(*) FILTER (WHERE tsi.sens_nm LIKE 'TTW%') AS ttw_count, COUNT(*) FILTER (WHERE tsi.sens_nm LIKE 'GNSS%') AS gnss_count, COUNT(*) FILTER (WHERE tsi.sens_nm LIKE 'TM%') AS tm_count, COUNT(*) FILTER (WHERE tsi.sens_nm LIKE 'RAIN%') AS rain_count FROM tb_sensor_info tsi
join tb_logger_info tli on tsi.logr_no = tli.logr_no and tli.district_no= #{district_no}
) s;

SELECT tad.sens_no, tad.meas_dt, tsi.sens_nm, tdi.district_nm, tad.sens_chnl_id, tad.alarm_lvl_cd, tad.formul_data, tad.net_err_yn, tad.maint_sts_cd, tai."1st_lvl_max" AS max1, tai."1st_lvl_min" AS min1, tai."2nd_lvl_max" AS max2, tai."2nd_lvl_min" AS min2, tai."3rd_lvl_max" AS max3, tai."3rd_lvl_min" AS min3, tai."4th_lvl_max" AS max4, tai."4th_lvl_min" AS min4, tad.reg_dt, tst.sens_tp_nm, tsc.sens_chnl_nm FROM tb_alarm_details tad LEFT JOIN tb_district_info tdi ON tad.district_no = tdi.district_no LEFT JOIN tb_sensor_info tsi ON tad.sens_no = tsi.sens_no LEFT JOIN tb_alarm_info tai ON tad.sens_no = tai.sens_no AND tad.sens_chnl_id = tai.sens_chnl_id LEFT JOIN tb_sensor_type tst ON tsi.senstype_no = tst.senstype_no LEFT JOIN tb_sensor_chnl tsc ON tad.sens_no = tsc.sens_no AND tad.sens_chnl_id = tsc.sens_chnl_id WHERE 1=1
and tad.district_no = #{district_no}
order by tad.reg_dt desc

